	static public $twistedIching=array('Hexagram_Name'=>'The Increated','Entity'=>'None', 'Logical'=>-1, 'Trigrams'=>[0,0],'Hexagram_Text'=>'The Twisted Philosophy of the Increated','Gain'=>'<span class="t13ne-chi-gain"><strong>Gain Chi</strong> when you prove you exist or capture a soul or send a soul to your masters.', 'Quest'=>'','QuestComplete'=>'', 'Unchanging'=>'Once per Scene you may discard all (applied, Stabilised, or currently being applied) Wounds.', 'Line1'=>'None','Line1Quest'=>'', 'Line1Gain'=>'N/a', 'Line2'=>'None','Line2Quest'=>'', 'Line2Gain'=>'N/a', 'Line3'=>'None','Line3Quest'=>'', 'Line3Gain'=>'N/a', 'Line4'=>'None','Line4Quest'=>'', 'Line4Gain'=>'N/a', 'Line5'=>'None','Line5Quest'=>'', 'Line5Gain'=>'N/a','Line6'=>'None','Line6Quest'=>'', 'Line6Gain'=>'N/a');

	public static function displayHexagram($hex=0, $twisted=0, $questing=FALSE, $display=true){
		if ($hex==-1){$twisted=true; $hex=0;}
		$hex=$hex%64;

		$entity=$twisted?self::$twistedIching['Entity']:self::$iching[$hex]['Entity'];
		$name=$twisted?self::$twistedIching['Hexagram_Name']:self::$iching[$hex]['Hexagram_Name'];
		$text=$twisted?self::$twistedIching['Hexagram_Text']:self::$iching[$hex]['Hexagram_Text'];
		$gain=$twisted?self::$twistedIching['Gain']:self::$iching[$hex]['Gain'];
		$trigrams = $twisted?self::$twistedIching['Trigrams']:self::$iching[$hex]['Trigrams'];
		$trigram_Text = '<div class="t13ne-trigrams"><details><summary>Trigrams</summary>'.self::displayTrigram($trigrams[1],$questing, 'Upper Trigram').self::displayTrigram($trigrams[0],$questing, 'Lower Trigram').'</details></div>';
		$logical = $twisted?self::$twistedIching['Logical']:self::$iching[$hex]['Logical'];
		$quest =  $twisted?self::$twistedIching['Quest']:self::$iching[$hex]['Quest'];
		$complete =  $twisted?self::$twistedIching['QuestComplete']:self::$iching[$hex]['QuestComplete'];
		$hex++;
		$hex+=-intval($twisted);
		if ($questing){
			$hText="<p class=\"t13ne-quest\"><strong>Quest: </strong><span class=\"t13ne-hex-quest\">{$quest}</span></p><p class=\"t13ne-quest-complete\"><strong>Quest Complete: </strong><span class=\"t13ne-hex-quest-complete\">{$complete}</span></p>";
		}
		if (!$questing){
			$hText = "<p><strong>Gains: </strong> <span class=\"t13ne-hex-gain\"> {$gain} </span></p>";
		}

		if ($questing&&$questing==="All"){
			$hText = "<p class=\"t13ne-quest\"><strong>Quest: </strong><span class=\"t13ne-hex-quest\">{$quest}</span></p><p class=\"t13ne-quest-complete\"><strong>Quest Complete: </strong><span class=\"t13ne-hex-quest-complete\">{$complete}</span></p><p><strong>Gains: </strong> <span class=\"t13ne-hex-gain\"> {$gain} </span></p>";
		}

		$ret="<figure class=\"t13ne-hexagram\" data-logical=\"$logical\"><h2 class=\"t13ne-hex-entity\">{$entity}</h2><span class=\"t13ne-hex-number\">({$hex}).</span> <strong class=\"t13ne-hex-title\">{$name}</strong><p class=\"t13ne-hex-text\">{$text}</p>{$trigram_Text}{$hText}</figure>";
		if ($display){
			return $ret;
		}else{
			return ['Main'=>$ret,'hex'=>$entity];
		}

	}
	public static function displayTrigram($trigram=0,$questing=false, $title='Trigram'){

		$trigram=$trigram%8;
		$logical = self::$trigrams[$trigram]['Logical'];
		$entity = self::$trigrams[$trigram]['Entity'];
		$name = self::$trigrams[$trigram]['Trigram_Name'];
		$desc = self::$trigrams[$trigram]['Description'];
		$quest = self::$trigrams[$trigram]['Quest'];
		$complication = self::$trigrams[$trigram]['Quest_Complication'];
		$steps = self::$trigrams[$trigram]['Quest_Steps'];
		$trigram++;
		return "<figure class=\"t13ne-trigram\" data-logical=\"$logical\"><h4>{$title}</h4><br/><h3 class=\"t13ne-tri-entity\">{$entity}</h3><span class=\"t13ne-tri-number\">({$trigram}). </span><strong class=\"t13ne-tri-title\">{$name}</strong><p class=\"t13ne-tri-desc\">{$desc}</p>".($questing?"<p class=\"t13ne-quest\"><strong>Quest: </strong><span class=\"t13ne-tri-quest\">{$quest}</span></p><p class=\"t13ne-quest-complication\"><strong>Quest Complication: </strong><span class=\"t13ne-tri-quest-complication\">{$complication}</span></p><p class=\"t13ne-quest-steps\"><strong>Quest Steps: </strong><span class=\"t13ne-tri-quest-steps\">{$steps}</span></p></figure>":"</figure>");
	}
	private static function binXor($pex,$fex){
		$bin1=''.base_convert(self::$iching[$pex%63]['Logical'],10,2);
		$bin2=''.base_convert(self::$iching[$fex%63]['Logical'],10,2);
		if (strlen($bin2)<strlen($bin1)){$bin2=str_repeat(0,strlen($bin1)-strlen($bin2)).$bin2;}
		if (strlen($bin1)<strlen($bin2)){$bin1=str_repeat(0,strlen($bin2)-strlen($bin1)).$bin1;}
		$bin1=str_split($bin1);
		$bin2=str_split($bin2);
		$out="";
		for ($i=0;$i<count($bin1);$i++){
		    // xor bit a bit
			$out.=(int)($bin1[$i])^(int)($bin2[$i]);
		}
		return base_convert(intval($out),2,10);
	}
	public static function displayChangingLine($hex1,$num,$b,$questing,$all){
		$line=self::$iching[$hex1]['Line'.$num];
		$gain=self::$iching[$hex1]['Line'.$num.'Gain'];
		$quest=self::$iching[$hex1]['Line'.$num.'Quest'];
		$rethtml="<li class=\"t13ne-cl-{$num}\" data-binary=\"$b\"><strong class=\"t13ne-changing-strong\"> Line {$num} \"{$line}\": </strong>";
		if ($questing||$all){
			$rethtml.="<br/><span class=\"t13ne-quest\"><strong>Quest line: </strong>{$quest}</span>";
		}

		if(!$questing||$all){
			$rethtml.="<br/><span class=\"t13ne-gain\"><strong>Character Gain: </strong>{$gain}</span>";
		}
		return $rethtml.'</li>';
	}
	public static function displayChangingLines($hex1,$hex2, $twisted=false, $questing=false, $all=false){
		if ($questing&&$questing==='All'){$all=true;}
		$rethtml='';
		$unchanging=self::$iching[$hex1]['Unchanging'];
		if ($hex1==$hex2||$twisted||$all){
			$rethtml .= "<section class=\"t13ne-hex-unchanging\"><strong>Unchanging Edge: </strong><span class=\"t13ne-hex-unchanging\">{$unchanging}</span></section>";
		}
		if ($hex1!==$hex2||$all){
			$cl=self::binXor($hex1,$hex2);

			$rethtml.='<section class="t13ne-changinglines" data-cl="'.$cl.'"><strong class="t13ne-changing">Changing Lines</strong><ul class="t13ne-changinglines">';
			for ($i=0;$i<6;$i++){
				$b=1<<$i;
				if ($cl&$b||$all){
					$num=$i+1;
					$rethtml.= self::displayChangingLine($hex1,$num,$b,$questing,$all);
				}

			}
			$rethtml.='</ul></section>';
		}
		return $rethtml;
	}
	public static function bookOfChanges(){
		$ret='';
		for ($i=0;$i<64;$i++){
			$ret.=self::displayHexagram($i,0,'All', true);
			$ret.=self::displayChangingLines($i,$i,false,'All',true);
		}
		$ret.=self::displayHexagram(-1,$i,'All', true);
		return $ret;
	}
	public static function displayIChing($hexagrams=-1,$hex2=-1, $twisted=false, $questing=false){
		if (is_array($hexagrams)){
			$hex1=$hexagrams[0];
			$hex2=$hexagrams[1];
		}else{
			$hex1=$hexagrams;
		}
		if ($hex2==-1||$hex2=='%'){$hex2=$hex1;}
		if ($hex1==-1||$hex1=='%'){$hex1=T13Dice::RNG(0,63);$hex2=T13Dice::RNG(0,63);}
		$hexa=self::displayHexagram($hex1,$twisted,$questing, false);
		$hexb=self::displayHexagram($hex2, $twisted,$questing,false);
		$rethtml='<details><summary><strong> Hexagrams: '.$hexa['hex'].' '.$hexb['hex'].'</strong></summary><article class="t13ne-hexagrams" data-hex=" '.$hex1.' " data-hex2=" '.$hex2.' ">';
		$rethtml.='<div class="t13ne-hex-present"><h4>Present</h4>'.$hexa['Main'].'</div>';
		$rethtml.='<div class="t13ne-hex-future"><h4>Future</h4>'.$hexb['Main'].'</div>';
		$rethtml.=self::displayChangingLines($hex1,$hex2,$twisted,$questing, false);
		$rethtml.='</article></details>';
		return $rethtml;
	}
	public static function displayTrigrams($trigrams,$questing=false, $titles=['Bottom','Top']){
		if ($trigrams){
			if (is_array($trigrams)){
				$ret = '<div class="t13ne-grams"><!-- '.json_encode( $trigrams ).'; -->';
				foreach($trigrams as $key=>$tri){
					$ret.='<!-- tri='.json_encode( $tri ).' -->';
					$ret .=self::displayTrigram($tri,$questing,$titles[$key]);
				}
				$ret.='</div>';
				return $ret;
			}else{
					//gonna assume a wild number got in here.
				return '<div class="t13ne-grams">'.self::displayTrigram($trigrams,$questing).'</div>';
			}
		}else{
			return 'No Trigrams found';
		}
	}
	public static function getLogical($number){
		$i=0;
		foreach(self::$iching as $hex){
			if ($number==$hex['Logical']){
				return $i;
			}
			$i++;
		}
	}

	static public function calcHexFromTrigrams($trigram1,$trigram2){
		return self::getLogical(self::$trigrams[$trigram2]['Logical']*4+self::$trigrams[$trigram1]['Logical']);
	}
	static public function getTrigrams($logicaltrigram){
		return [self::getLogicalTrigram($logicaltrigram[0]),self::getLogicalTrigram($logicaltrigram[1])];

	}
	static public function calculateLogicalTrigram($taos){
		$result = [0,0];
		foreach ($taos as $key => $tao) {
			$result = [$result[0]+$tao[0],$result[1]+$tao[1]];
		}
		return $result;
	}
	static public function getLogicalTrigram($number){
		$i=0;
		foreach(self::$trigrams as $tri){
			if ($number==$tri['Logical']){
				return $i;
			}
			$i++;
		}
	}
	public static function calculateIChing($stats){
			//var_dump($stats);
		if (array_key_exists('Stats', $stats)){$stats=$stats['Stats'];}
		$logical=array(0,0);
		$i=0;
		foreach ($stats as $statpair){
			if (($statpair['Facet_Boon']+$statpair['Facet_Mutation_Matrix'])>($statpair['Antifacet_Boon']+$statpair['Antifacet_Mutation_Matrix'])){
				$logical[$i>5]+=1<<$i;
			}
			if (($statpair['Facet_Boon']+$statpair['Facet_Mutation_Matrix'])==($statpair['Antifacet_Boon']+$statpair['Antifacet_Mutation_Matrix'])){
				$logical [$i>5]+= T13Dice::RNG(0,1)<<$i;
			}
				//var_dump($logical);
			$i++;
		}
		$logical[1]=$logical[1]>>7;
			//var_dump($logical);
		$hex=array(self::getLogical($logical[0]),self::getLogical($logical[1]));
		return $hex;
	}
}
